(47, 3, 34, '); };\n\n// Logout\n\nexport const logout = () => {\n\nlocalStorage.removeItem(\n\n\"token\"\n\nGanti seluruh isi src/pages/Login.jsx Menjadi: import { useState } from \"react\"; import { useNavigate } from \"react-router-dom\"; import { login, saveToken } from \"../services/authService\"; function Login() { const navigate = useNavigate(); const [email, setEmail] = useState(\"\"); const [password, setPassword] = useState(\"\"); const [loading, setLoading] = useState(false); const submitLogin = async (e) => { e.preventDefault(); try { setLoading(true); const data = await login( email, password ); saveToken( data.token ); if (data.role === \"guru\") { navigate(\"/guru\"); } else { navigate(\"/siswa\"); } } catch (err) { alert( err.response?.data?.message || \"Login gagal\" ); } finally { setLoading(false); } }; return ( <div className=\"container\"> <div className=\"row justify-content-center mt-5\"> <div className=\"col-md-5\"> <div className=\"card shadow\"> <div className=\"card-body\"> <h3 className=\"text-center mb-4\"> Chatbot NLP </h3> <form onSubmit={submitLogin}> <div className=\"mb-3\"> <label> Email </label> <input type=\"email\" className=\"form-control\" value={email} onChange={(e)=> setEmail( e.target.value ) } required /> </div> <div className=\"mb-3\"> <label> Password </label> <input type=\"password\" className=\"form-control\" value={password} onChange={(e)=> setPassword( e.target.value ) } required /> </div> <button className=\"btn btn-primary w-100\" disabled={loading} > { loading ? \"Loading...\" : \"Login\" } </button> </form> </div> </div> </div> </div> </div> ); } export default Login;', '2026-07-22 12:30:46', NULL, 18),
