(62, 3, 49, 'import { useEffect, useState } from \"react\"; import { getMateri } from \"../services/materiService\"; import { askChatbot } from \"../services/chatbotService\"; function Chatbot() { const [materi, setMateri] = useState([]); const [materiId, setMateriId] = useState(\"\"); const [pertanyaan, setPertanyaan] = useState(\"\"); const [jawaban, setJawaban] = useState(\"\"); const [status, setStatus] = useState(\"\"); const [similarity, setSimilarity] = useState(\"\"); const [loading, setLoading] = useState(false); // ========================== // Load daftar materi // ========================== useEffect(() => { loadMateri(); }, []); const loadMateri = async () => { try { const data = await getMateri(); setMateri(data); } catch (err) { console.log(err); } }; // ========================== // Kirim Pertanyaan // ========================== const kirimPertanyaan = async () => { if (!materiId) { alert(\"Pilih materi terlebih dahulu\"); return; } if (!pertanyaan) { alert(\"Pertanyaan tidak boleh kosong\"); return; } try { setLoading(true); const hasil = await askChatbot( materiId, pertanyaan ); setJawaban( hasil.jawaban ); setStatus( hasil.status ); setSimilarity( hasil.similarity ); } catch (err) { console.log(err); alert( err.response?.data?.message || \"Terjadi kesalahan\" ); } finally { setLoading(false); } }; return ( <div className=\"container mt-5\"> <div className=\"card shadow\"> <div className=\"card-header bg-primary text-white\"> <h3> Chatbot Pembelajaran </h3> </div> <div className=\"card-body\"> <div className=\"mb-3\"> <label> Pilih Materi </label> <select className=\"form-select\" value={materiId} onChange={(e)=> setMateriId( e.target.value ) } > <option value=\"\"> -- Pilih Materi -- </option> { materi.map((item)=>( <option key={item.id} value={item.id} > {item.judul} </option> )) } </select> </div> <div className=\"mb-3\"> <label> Pertanyaan </label> <textarea rows=\"4\" className=\"form-control\" value={pertanyaan} onChange={(e)=> setPertanyaan( e.target.value ) } /> </div> <button className=\"btn btn-success\" onClick={kirimPertanyaan} disabled={loading} > { loading ? \"Memproses...\" : \"Kirim Pertanyaan\" } </button> <hr /> <h5> Jawaban Chatbot </h5> <div className=\"border rounded p-3 bg-light\"> { jawaban || \"Belum ada jawaban.\" } </div> { jawaban && ( <> <hr /> <p> <b>Status :</b> {\" \"} {status} </p> <p> <b>Similarity :</b> {\" \"} {similarity} </p> </> ) } </div> </div> </div> ); } export default Chatbot;', '2026-07-22 12:30:46', NULL, 25),
(63, 3, 50, 'hasil:\n\nTambahan Part 4a Boleh dikerjakan Boleh tidak\n\nAnalisis Selanjutnya jika pada project saat ini jawaban akan mengambil keseluruhan teks yang ada pada chunk sehingga jawaban lebih Panjang dan penanya harus mencari sendiri jawaban yang diinginkan setelah membaca seluruh chunk yang diberikan oleh sistem tersebut. Oleh karena itu perlu dilakukan Extractive Question Answering (Extractive QA). Extractive QA adalah metode Question Answering (QA) di mana sistem tidak membuat jawaban baru, tetapi mengambil (extract) potongan teks yang paling relevan dari dokumen atau materi yang tersedia untuk menjawab pertanyaan pengguna. Selain itu jika dianalisis hasil jawaban terkadang masih ngambang, ingat sebelumnya algoritma yang digunakan secara urut: Upload Materi Pecah materi menjadi chunk Batasi chunk berdasarkan jumlah kata Dengan pemotongan jumlah kata tersebut, membuat suatu informasi terkadang terpenggal sehingga jawaban menjadi tidak relevan, oleh karena itu otak chatbot masih perlu kita perbaiki dengan tahapan:', '2026-07-22 12:30:46', NULL, 4),
(64, 3, 51, 'Tahap 1: Ubah chunking menjadi berbasis paragraf (bukan jumlah karakter). Tahap 2 : Retrieval dua tahap (Chunk → Kalimat). Tahap 3 : Dynamic Answer (1–3 kalimat berdasarkan skor). Tahap 4: Threshold agar chatbot bisa mengatakan \"Jawaban tidak ditemukan\" jika memang tidak relevan. Tahap 5: tambahkan referensi sumber (judul materi, nomor chunk, atau heading jika tersedia).', '2026-07-22 12:30:46', NULL, 6),
(65, 3, 52, 'Untuk hal tersebut perlu diperbaiki beberapa hal sesuai urutan berikut\n\nTabel materi_chunks Update tabel materi_chunks dengan menambahkan field “heading” dan “Sentence Count” sehingga menjadi seperti:', '2026-07-22 12:30:46', NULL, 1),
(66, 3, 53, 'Tujuan penambahan ini agar data tersimpan dengan lebih detail\n\nUpdate backend/models/chunk_model.py Karena tabel berganti maka model chunks juga berganti, sesuaikan code menjadi: from database import db', '2026-07-22 12:30:46', NULL, 2),
(67, 3, 54, 'class MateriChunk(db.Model):\n\n__tablename__ = \"materi_chunks\"\n\nid = db.Column( db.Integer, primary_key=True )\n\nmateri_id = db.Column( db.Integer, db.ForeignKey(\"materi.id\") )', '2026-07-22 12:30:46', NULL, 8),
