(69, 3, 56, 'sentence_count = db.Column( db.Integer, default=0 )\n\ncreated_at = db.Column( db.DateTime, server_default=db.func.now() )', '2026-07-22 12:30:46', NULL, 7),
(70, 3, 57, 'Ganti kode backend/services/chunk_service.py import re def clean_paragraph(paragraph): paragraph = paragraph.strip() paragraph = re.sub( r\"\\s+\", \" \", paragraph ) return paragraph def split_into_chunks( text, min_length=120 ): paragraphs = re.split( r\"\\n\\s*\\n\", text ) hasil = [] current = \"\" index = 0 for p in paragraphs: p = clean_paragraph(p) if len(p) < 5: continue if len(current) < min_length: current += \"\\n\\n\" + p else: hasil.append({ \"index\": index, \"text\": current.strip() }) current = p index += 1 if current: hasil.append({ \"index\": index, \"text\": current.strip() }) return hasil', '2026-07-22 12:30:46', NULL, 9),
(71, 3, 58, 'Revisi materi_routes.py Karena tabel berubah, chunk juga berubah, maka tentu upload juga harus di robah, buka file backend/routes/materi_routes.py Awal:', '2026-07-22 12:30:46', NULL, 3),
(72, 3, 59, 'Ganti seperti gambar disamping kanan.\n\nRevisi chatbot_routes.py Ganti seluruh code menjadi: from flask import Blueprint from flask import request from flask import jsonify from flask_jwt_extended import ( jwt_required, get_jwt_identity ) from database import db from models.materi_model import Materi from models.chat_model import ChatHistory from services.retrieval_service import retrieve_chunks from services.answer_service import build_answer chatbot_bp = Blueprint( \"chatbot\", __name__ ) @chatbot_bp.route( \"/ask\", methods=[\"POST\"] ) @jwt_required() def ask(): try: data = request.get_json() materi_id = data.get(\"materi_id\") pertanyaan = data.get(\"pertanyaan\") if not materi_id: return jsonify({ \"message\": \"Materi harus dipilih.\" }), 400 if not pertanyaan: return jsonify({ \"message\": \"Pertanyaan tidak boleh kosong.\" }), 400 materi = Materi.query.get(materi_id) if materi is None: return jsonify({ \"message\": \"Materi tidak ditemukan.\" }), 404', '2026-07-22 12:30:46', NULL, 16),
(73, 3, 60, '# Retrieval NLP v2\n\nhasil = retrieve_chunks( materi_id=materi_id, pertanyaan=pertanyaan, top_chunk=5, top_sentence=5 ) if len(hasil) == 0: return jsonify({ \"message\": \"Tidak ada chunk yang ditemukan.\" }), 404 similarity = hasil[0][\"score\"] confidence = round( similarity * 100, 2 ) if similarity >= 0.80: status = \"Sangat Relevan\" elif similarity >= 0.60: status = \"Relevan\" elif similarity >= 0.40: status = \"Cukup Relevan\" else: status = \"Tidak Relevan\" if similarity >= 0.40: jawaban = build_answer( pertanyaan, hasil ) else: jawaban = ( \"Maaf, saya tidak menemukan jawaban \" \"yang cukup relevan pada materi ini.\" ) chat = ChatHistory( user_id=int( get_jwt_identity() ), materi_id=materi_id, pertanyaan=pertanyaan, jawaban=jawaban, similarity_score=similarity, status=status ) db.session.add(chat) db.session.commit() return jsonify({ \"jawaban\": jawaban, \"status\": status, \"confidence\": confidence, \"similarity\": round( similarity, 4 ), \"materi\": materi.judul, \"referensi\": [ { \"score\": round( item[\"score\"], 4 ), \"preview\": item[\"text\"][:180] } for item in hasil ] }) except Exception as e: db.session.rollback() return jsonify({ \"message\": str(e) }), 500', '2026-07-22 12:30:46', NULL, 14),
(74, 3, 61, 'Revisi backend/services/retrieval_service.py Saat ini kode program baru mengambil jawaban dari satu chunk, bagaimana jika jawaban berada pada beberapa chunk berbeda, sehingga perlu diperbaiki pada bagian retrieval_Service menjadi : from models.chunk_model import MateriChunk from services.nlp_service import similarity def retrieve_chunks( materi_id, pertanyaan, top_chunk=5, top_sentence=5 ): semua_chunk = MateriChunk.query.filter_by( materi_id=materi_id ).all() hasil_chunk = []', '2026-07-22 12:30:46', NULL, 7),
(75, 3, 62, '# Ranking Chunk\n\nfor chunk in semua_chunk: score = similarity( chunk.chunk_text, pertanyaan ) hasil_chunk.append({ \"text\": chunk.chunk_text, \"score\": score }) hasil_chunk.sort( key=lambda x: x[\"score\"], reverse=True ) hasil_chunk = hasil_chunk[:top_chunk]', '2026-07-22 12:30:46', NULL, 5),
(76, 3, 63, '# Ranking Sentence\n\nhasil_sentence = [] for item in hasil_chunk: kalimat = item[\"text\"].split(\".\") for sentence in kalimat: sentence = sentence.strip() if len(sentence) < 10: continue score = similarity( sentence, pertanyaan ) hasil_sentence.append({ \"text\": sentence, \"score\": score }) hasil_sentence.sort( key=lambda x: x[\"score\"], reverse=True ) return hasil_sentence[:top_sentence]', '2026-07-22 12:30:46', NULL, 6),
(77, 3, 64, 'Revisi backend/services/answer_service.py setelah beberapa update pada beberapa pemanggilan informasi, tentu answer_Service juga perlu diperbaiki: def build_answer( pertanyaan, hasil_sentence ): if len(hasil_sentence) == 0: return ( \"Maaf, saya tidak menemukan jawaban yang relevan.\" ) terbaik = hasil_sentence[0][\"score\"] if terbaik < 0.25: return ( \"Maaf, jawaban tidak ditemukan pada materi.\" ) if terbaik > 0.80: jumlah = 1 elif terbaik > 0.60: jumlah = 2 else: jumlah = 3 jawaban = \"Berdasarkan materi:\\n\\n\" sudah = set() for item in hasil_sentence: if len(sudah) >= jumlah: break if item[\"text\"] in sudah: continue sudah.add( item[\"text\"] ) jawaban += \"• \" jawaban += item[\"text\"] jawaban += \"\\n\" return jawaban', '2026-07-22 12:30:46', NULL, 8),
(78, 3, 65, 'Testing Lakukan Pengujian hasil Sistem: Jalankan (venv) backend, Buka terminal baru, pastikan sudah masuk (venv) dan berada pada directroy backend jalankan python app.py Jalankan frontend Tanpa menutup terminal backend sebelumnya, buka new terminal, jika masih ada tanda (venv) deactivate terlebih dahulu, pindah direktori ke frontend, dengan cd frontend jalankan frontend dengan npm run dev hasilnya akan menampilkan informasi yang lebih akurat. Hasil menjadi lebih ringkas dan to the point, Dan terlihat jika jawaban juga memberikan pada informasi terkait pada bagian mana materi tersebut berada, sehingga akan memudahkan siswa untuk membaca materi lansung ke bagian yang diinginkan.', '2026-07-22 12:30:46', NULL, 4);

